API_name: nchu_cross_program_search_by_program
Description:
{
  "description": "依學程名稱查詢學分學程課程（如永續環境學分學程、人工智慧學分學程）。",
  "required_parameters": [
    {
      "name": "program_name",
      "type": "STRING",
      "description": "學程名稱（支援部分比對）"
    }
  ],
  "optional_parameters": [
    {
      "name": "semester",
      "type": "STRING",
      "description": "學年期代碼",
      "default": null
    },
    {
      "name": "degree_type",
      "type": "STRING",
      "description": "學制：U=大學部, G=研究生",
      "default": null
    }
  ]
}

